// npm install mysql2 dotenv
const mysql = require('mysql2/promise'); // versi Promise
require('dotenv').config();

// ==========================================
// SETUP CONNECTION POOL
// ==========================================
const pool = mysql.createPool({
  host:               process.env.DB_HOST     || 'localhost',
  port:               process.env.DB_PORT     || 3306,
  user:               process.env.DB_USER     || 'root',
  password:           process.env.DB_PASSWORD,
  database:           process.env.DB_NAME     || 'web_belajar',
  waitForConnections: true,
  connectionLimit:    10,   // maksimal 10 koneksi bersamaan
  queueLimit:         0,    // antrian tidak terbatas
  charset:            'utf8mb4'
});

// Test koneksi saat startup
async function testKoneksi() {
  try {
    const conn = await pool.getConnection();
    console.log('✅ Database terhubung!');
    conn.release(); // kembalikan koneksi ke pool
  } catch (err) {
    console.error('❌ Gagal terhubung ke database:', err.message);
    process.exit(1);
  }
}
testKoneksi();

// ==========================================
// QUERY DASAR — Selalu gunakan ? untuk nilai!
// ==========================================

// SELECT dengan prepared statement
async function getMahasiswaById(id) {
  const [rows] = await pool.execute(
    'SELECT m.*, j.nama AS jurusan FROM mahasiswa m JOIN jurusan j ON m.jurusan_id = j.id WHERE m.id = ?',
    [id]  // nilai dikirim terpisah, AMAN dari SQL Injection
  );
  return rows[0] || null; // kembalikan satu object atau null
}

// SELECT dengan filter dinamis
async function getMahasiswaByFilter({ jurusan_id, is_aktif, search, limit = 10, offset = 0 }) {
  let sql = 'SELECT m.nim, m.nama, m.ipk, j.nama AS jurusan FROM mahasiswa m JOIN jurusan j ON m.jurusan_id = j.id WHERE 1=1';
  const params = [];

  if (jurusan_id) { sql += ' AND m.jurusan_id = ?'; params.push(jurusan_id); }
  if (is_aktif !== undefined) { sql += ' AND m.is_aktif = ?'; params.push(is_aktif); }
  if (search) { sql += ' AND m.nama LIKE ?'; params.push(`%${search}%`); }

  sql += ' ORDER BY m.nama LIMIT ? OFFSET ?';
  params.push(limit, offset);

  const [rows] = await pool.execute(sql, params);
  return rows;
}

// INSERT
async function createMahasiswa({ nim, nama, email, jurusan_id }) {
  const [result] = await pool.execute(
    'INSERT INTO mahasiswa (nim, nama, email, jurusan_id) VALUES (?, ?, ?, ?)',
    [nim, nama, email, jurusan_id]
  );
  return result.insertId; // ID dari baris yang baru dibuat
}

// ==========================================
// TRANSAKSI — semua atau tidak sama sekali
// ==========================================
async function daftarMahasiswaDanKRS(dataMahasiswa, dataKRS) {
  const conn = await pool.getConnection();
  try {
    await conn.beginTransaction();

    // Operasi 1: buat mahasiswa baru
    const [result] = await conn.execute(
      'INSERT INTO mahasiswa (nim, nama, email, jurusan_id) VALUES (?, ?, ?, ?)',
      [dataMahasiswa.nim, dataMahasiswa.nama, dataMahasiswa.email, dataMahasiswa.jurusan_id]
    );
    const mahasiswaId = result.insertId;

    // Operasi 2: daftarkan ke KRS
    for (const matkul of dataKRS) {
      await conn.execute(
        'INSERT INTO krs (mahasiswa_id, matkul_id, semester) VALUES (?, ?, ?)',
        [mahasiswaId, matkul.id, matkul.semester]
      );
    }

    await conn.commit(); // semua berhasil — simpan permanen
    return mahasiswaId;

  } catch (err) {
    await conn.rollback(); // ada yang gagal — batalkan semua
    throw err;
  } finally {
    conn.release(); // kembalikan koneksi ke pool
  }
}

// npm install sequelize mysql2
const { Sequelize, DataTypes, Op } = require('sequelize');

// ==========================================
// SETUP KONEKSI
// ==========================================
const sequelize = new Sequelize(
  process.env.DB_NAME,
  process.env.DB_USER,
  process.env.DB_PASSWORD,
  {
    host:    process.env.DB_HOST || 'localhost',
    dialect: 'mysql',
    logging: process.env.NODE_ENV === 'development' ? console.log : false,
    pool: { max: 10, min: 0, acquire: 30000, idle: 10000 }
  }
);

// ==========================================
// DEFINISI MODEL
// ==========================================
const Jurusan = sequelize.define('Jurusan', {
  id:   { type: DataTypes.INTEGER, primaryKey: true, autoIncrement: true },
  kode: { type: DataTypes.STRING(5), allowNull: false, unique: true },
  nama: { type: DataTypes.STRING(100), allowNull: false }
}, { tableName: 'jurusan', timestamps: false });

const Mahasiswa = sequelize.define('Mahasiswa', {
  id:    { type: DataTypes.INTEGER, primaryKey: true, autoIncrement: true },
  nim:   { type: DataTypes.STRING(10), allowNull: false, unique: true },
  nama:  { type: DataTypes.STRING(100), allowNull: false },
  email: { type: DataTypes.STRING(150), allowNull: false, unique: true,
           validate: { isEmail: true } },  // validasi bawaan Sequelize
  ipk:   { type: DataTypes.DECIMAL(3, 2), defaultValue: 0.00,
           validate: { min: 0, max: 4 } },
  isAktif: { type: DataTypes.BOOLEAN, defaultValue: true, field: 'is_aktif' }
}, { tableName: 'mahasiswa', underscored: true });

// ==========================================
// ASOSIASI
// ==========================================
Jurusan.hasMany(Mahasiswa, { foreignKey: 'jurusan_id', as: 'mahasiswa' });
Mahasiswa.belongsTo(Jurusan, { foreignKey: 'jurusan_id', as: 'jurusan' });

// ==========================================
// CRUD DENGAN SEQUELIZE
// ==========================================

// findAll: ambil semua dengan filter
async function getDaftarMahasiswa({ jurusan_id, search, halaman = 1, limit = 10 }) {
  const offset = (halaman - 1) * limit;

  const { count, rows } = await Mahasiswa.findAndCountAll({
    where: {
      isAktif: true,
      ...(jurusan_id && { jurusan_id }),
      ...(search && { nama: { [Op.like]: `%${search}%` } })
    },
    include: [{ model: Jurusan, as: 'jurusan', attributes: ['kode', 'nama'] }],
    order: [['nama', 'ASC']],
    limit,
    offset
  });

  return {
    data: rows,
    pagination: { total: count, halaman, limit, totalHalaman: Math.ceil(count / limit) }
  };
}

// findOne: cari satu
async function getMahasiswaByNim(nim) {
  return await Mahasiswa.findOne({
    where: { nim },
    include: [{ model: Jurusan, as: 'jurusan' }]
  });
}

// create: buat baru
async function buatMahasiswa(data) {
  return await Mahasiswa.create(data);
  // Sequelize otomatis validasi berdasarkan schema model
}

// update: ubah
async function updateIPK(nim, ipkBaru) {
  const [jumlahTerpengaruh] = await Mahasiswa.update(
    { ipk: ipkBaru },
    { where: { nim } }
  );
  return jumlahTerpengaruh > 0;
}

// destroy: hapus
async function hapusMahasiswa(id) {
  const jumlah = await Mahasiswa.destroy({ where: { id } });
  return jumlah > 0;
}
